import{_ as e,o,c as s,ag as i}from"./chunks/framework.ByAj6Cie.js";const m=JSON.parse('{"title":"Caídas de voltaje","description":"","frontmatter":{},"headers":[],"relativePath":"es/power-quality/voltage-sags.md","filePath":"es/power-quality/voltage-sags.md"}'),r={name:"es/power-quality/voltage-sags.md"};function n(l,a,d,t,c,p){return o(),s("div",null,[...a[0]||(a[0]=[i('<h1 id="caidas-de-voltaje" tabindex="-1">Caídas de voltaje <a class="header-anchor" href="#caidas-de-voltaje" aria-label="Permalink to &quot;Caídas de voltaje&quot;">​</a></h1><h2 id="descripcion-general" tabindex="-1">Descripción general <a class="header-anchor" href="#descripcion-general" aria-label="Permalink to &quot;Descripción general&quot;">​</a></h2><p>Las caídas de voltaje son reducciones de corta duración en la magnitud del voltaje, que típicamente duran desde unos pocos milisegundos hasta unos pocos segundos.</p><p>Son una de las perturbaciones de calidad de energía más comunes en sistemas industriales y pueden afectar la operación del equipo incluso cuando la reducción es relativamente pequeña.</p><p>Las caídas de voltaje no interrumpen completamente la potencia, pero la reducen por debajo de los niveles normales.</p><h2 id="proposito" tabindex="-1">Propósito <a class="header-anchor" href="#proposito" aria-label="Permalink to &quot;Propósito&quot;">​</a></h2><p>Comprender las caídas de voltaje es importante para:</p><ul><li>Prevenir apagados inesperados del equipo</li><li>Mantener la continuidad de los procesos industriales</li><li>Proteger dispositivos electrónicos sensibles</li><li>Mejorar la confiabilidad del sistema</li></ul><p>La gestión de caídas de voltaje reduce las pérdidas de producción y las interrupciones operativas.</p><h2 id="como-funciona" tabindex="-1">Cómo funciona <a class="header-anchor" href="#como-funciona" aria-label="Permalink to &quot;Cómo funciona&quot;">​</a></h2><p>Una caída de voltaje ocurre cuando hay un aumento súbito en la demanda de corriente o una falla en el sistema.</p><p>Esto provoca una caída temporal de voltaje debido a la impedancia del sistema.</p><p>Las causas comunes incluyen:</p><ul><li>Arranque de motores, especialmente motores de gran tamaño</li><li>Cortocircuitos o fallas en sistemas cercanos</li><li>Energización de transformadores o cargas pesadas</li><li>Perturbaciones de la compañía eléctrica que afectan el suministro</li></ul><p>La severidad de una caída depende de:</p><ul><li>Profundidad de la reducción de voltaje</li><li>Duración del evento</li><li>Sensibilidad del equipo conectado</li></ul><p>Incluso caídas breves pueden provocar que los sistemas de control o variadores se disparen.</p><h2 id="aplicaciones" tabindex="-1">Aplicaciones <a class="header-anchor" href="#aplicaciones" aria-label="Permalink to &quot;Aplicaciones&quot;">​</a></h2><p>Las consideraciones sobre caídas de voltaje son importantes en:</p><ul><li>Sistemas accionados por motores, como bombas y compresores</li><li>Líneas de producción automatizadas</li><li>Sistemas de control basados en PLC</li><li>Variadores de frecuencia y electrónica de potencia</li><li>Instalaciones con procesos continuos</li></ul><p>Son críticas en entornos donde incluso interrupciones breves afectan la producción.</p><h2 id="consideraciones-clave" tabindex="-1">Consideraciones clave <a class="header-anchor" href="#consideraciones-clave" aria-label="Permalink to &quot;Consideraciones clave&quot;">​</a></h2><ul><li><p><strong>Profundidad de la caída</strong><br> Una mayor reducción de voltaje incrementa la probabilidad de mal funcionamiento del equipo</p></li><li><p><strong>Duración</strong><br> Caídas más prolongadas tienen mayor probabilidad de provocar disparos o apagados</p></li><li><p><strong>Sensibilidad de la carga</strong><br> Los dispositivos electrónicos son más sensibles que las cargas resistivas</p></li><li><p><strong>Robustez del sistema</strong><br> Los sistemas con menor impedancia experimentan caídas de voltaje menores</p></li><li><p><strong>Métodos de arranque</strong><br> Las técnicas de arranque de motores pueden reducir el impacto de las caídas</p></li><li><p><strong>Coordinación con la protección</strong><br> Los ajustes de protección deben evitar disparos innecesarios durante caídas temporales</p></li></ul><h2 id="notas-practicas" tabindex="-1">Notas prácticas <a class="header-anchor" href="#notas-practicas" aria-label="Permalink to &quot;Notas prácticas&quot;">​</a></h2><ul><li>El arranque de motores de gran tamaño es una causa interna común de caídas de voltaje</li><li>Los variadores y sistemas de control suelen dispararse antes de que los motores se vean afectados</li><li>Los arrancadores suaves y variadores de velocidad pueden reducir la severidad de las caídas</li><li>Separar las cargas sensibles de las cargas pesadas mejora la estabilidad</li><li>El monitoreo ayuda a identificar la fuente y la frecuencia de los eventos de caída</li></ul>',25)])])}const v=e(r,[["render",n]]);export{m as __pageData,v as default};
